-- ─────────────────────────────────────────────────────────────────────────
-- seed_frames.sql — DATA DEFAULT frame (21 frame) hasil setup admin.
-- Tujuan: device lain yang clone repo punya frame SAMA PERSIS di setup awal.
--
-- SIFAT: SEKALI SEED SAJA (once per database).
--   Diproteksi tabel penanda `seed_flags` (key = frames_snapshot_v1).
--   * DB baru & belum ada penanda  -> seluruh frame di-apply, penanda diset.
--   * Sudah ada penanda (pernah    -> SELURUH blok DILEWATI. Editan admin
--     diseed / pull ulang / reboot)   TIDAK di-reset. AMAN diulang.
--
-- Jalankan di device baru (setelah init.sql & folder frames/ ada):
--   psql "$DATABASE_URL" -f backend/migrations/seed_frames.sql
--
-- Kalau nanti frame diubah lagi & mau jadi default baru: regenerate file ini
-- dan naikkan versi penanda ke frames_snapshot_v2 (dst) supaya di-apply ulang
-- SEKALI di device yang sudah ada. (minta Claude regenerate.)
-- ─────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS seed_flags (
  key        TEXT PRIMARY KEY,
  applied_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

DO $seed$
BEGIN
  IF EXISTS (SELECT 1 FROM seed_flags WHERE key = 'frames_snapshot_v1') THEN
    RAISE NOTICE 'seed_frames: frames_snapshot_v1 sudah diterapkan - dilewati (editan admin tidak di-reset).';
    RETURN;
  END IF;

